73	/// Expand leading `~` to the user's home directory.
74	fn expand_tilde(path: &str) -> PathBuf {
75	    if let Some(rest) = path.strip_prefix("~/") {
76	        dirs::home_dir()
77	            .expect("Cannot determine home directory")
78	            .join(rest)
79	    } else if path == "~" {
80	        dirs::home_dir().expect("Cannot determine home directory")
81	    } else {
82	        PathBuf::from(path)
83	    }
84	}
