86	#[tokio::main]
87	async fn main() -> Result<()> {
88	    let _ = custom_utils::logger::logger_feature(
89	        "system-prompt-show",
90	        "debug,reqwest=info,hyper_util=info",
91	        log::LevelFilter::Info,
92	        false,
93	    )
94	    .build();
95	
96	    let cli = Cli::parse();
97	
98	    if cli.help {
99	        print_help_and_config(&cli.config)?;
100	        return Ok(());
101	    }
102	
103	    match cli.command.unwrap_or(Commands::Serve) {
104	        Commands::Serve => {
105	            let config_path = expand_tilde(&cli.config);
106	            let config = load_config(&config_path)?;
107	            run_service(config).await?;
108	        }
109	        Commands::Clear { db_path } => {
110	            // Expand path and delete database files
111	            let db_path = match db_path {
112	                Some(path) => expand_tilde(&path),
113	                None => resolve_db_path_from_config(&cli.config)?,
114	            };
115	            // Remove primary db file
116	            let _ = fs::remove_file(&db_path);
117	            // Also remove SQLite journal files if they exist
118	            let shm_path = db_path.with_extension("db-shm");
119	            let wal_path = db_path.with_extension("db-wal");
120	            let _ = fs::remove_file(&shm_path);
121	            let _ = fs::remove_file(&wal_path);
122	            println!("Database files removed: {}", db_path.display());
123	        }
124	        Commands::Init => {
125	            let ca_dir = app_dir();
126	            let _ca = CertAuthority::load_or_generate(&ca_dir)?;
127	            let cert_path = ca_dir.join("ca.crt");
128	            println!("CA certificate: {}", cert_path.display());
129	            println!();
130	            println!("To trust on Linux:");
131	            println!(
132	                "  sudo cp {} /usr/local/share/ca-certificates/system-prompt-show.crt",
133	                cert_path.display()
134	            );
135	            println!("  sudo update-ca-certificates");
136	            println!();
137	            println!("For Node.js-based clients only:");
138	            println!("  export NODE_EXTRA_CA_CERTS={}", cert_path.display());
139	            println!();
140	            println!(
141	                "Codex should prefer system trust unless you have confirmed it uses Node TLS."
142	            );
143	        }
144	    }
145	
146	    Ok(())
147	}
