149	async fn run_service(config: AppConfig) -> Result<()> {
150	    let db_path = expand_tilde(&config.db_path);
151	    SqliteStorage::new(&db_path)?;
152	
153	    // Shared infrastructure: event bus, storage worker, web server
154	    let (event_tx, _event_rx) = broadcast::channel::<AppEvent>(256);
155	    let storage_tx = spawn_storage_worker(&db_path, &config.web, &event_tx)?;
156	    spawn_web_server_if_enabled(&db_path, &config.web, &event_tx);
157	
158	    let mut join_set = JoinSet::new();
159	
160	    // Always start the proxy service
161	    {
162	        let ca_dir = app_dir();
163	        let ca = CertAuthority::load_or_generate(&ca_dir)?;
164	        info!("CA loaded from {}", ca_dir.display());
165	
166	        let cert_cache = Arc::new(CertCache::new(ca));
167	        let upstream_parsed = upstream::Upstream::parse(&config.proxy.upstream)?;
168	        let db = SqliteStorage::new(&db_path)?;
169	        let (capture_tx, capture_rx) = mpsc::unbounded_channel::<CapturedPrompt>();
170	
171	        print_banner(config.proxy.port, &config.proxy.upstream, &db_path);
172	
173	        let display_config = DisplayConfig {
174	            verbose: config.proxy.verbose,
175	            filter: config.proxy.filter.clone(),
176	            output: config.proxy.output.clone(),
177	            no_console: config.proxy.no_console,
178	        };
179	        tokio::spawn(async move {
180	            run_display(capture_rx, display_config, db).await;
181	        });
182	
183	        let fixture_dumper = config
184	            .proxy
185	            .dump_fixtures
186	            .clone()
187	            .map(|dir| Arc::new(FixtureDumper::new(dir)));
188	        let registry = Arc::new(capture::extractor::ExtractorRegistry::new());
189	        let proxy_runtime = ProxyRuntime {
190	            cert_cache,
191	            capture_tx,
192	            registry,
193	            fixture_dumper,
194	            storage_tx: storage_tx.clone(),
195	        };
196	        let proxy_host = config.proxy.host.clone();
197	        let proxy_port = config.proxy.port;
198	        join_set.spawn(async move {
199	            proxy::run_proxy(
200	                &proxy_host,
201	                proxy_port,
202	                Arc::new(upstream_parsed),
203	                proxy_runtime,
204	            )
205	            .await
206	        });
207	    }
208	
209	    // Start relay sites if configured
210	    for site in config.relay.sites.clone() {
211	        let storage_tx = storage_tx.clone();
212	        let db_path = db_path.clone();
213	        info!(
214	            "Starting relay site '{}': {}:{} -> {}",
215	            site.name, site.host, site.port, site.upstream
216	        );
217	        join_set.spawn(async move {
218	            relay::run_relay_server(&site.host, site.port, site.upstream, storage_tx, &db_path)
219	                .await
220	        });
221	    }
222	
223	    // Wait for any service to finish (or fail)
224	    while let Some(result) = join_set.join_next().await {
225	        match result {
226	            Ok(Ok(())) => {}
227	            Ok(Err(err)) => return Err(err),
228	            Err(err) => return Err(err.into()),
229	        }
230	    }
231	
232	    Ok(())
233	}
