235	fn spawn_storage_worker(
236	    db_path: &Path,
237	    web_config: &config::WebUiConfig,
238	    event_tx: &broadcast::Sender<AppEvent>,
239	) -> Result<mpsc::UnboundedSender<StorageCommand>> {
240	    let (storage_tx, storage_rx) = mpsc::unbounded_channel::<StorageCommand>();
241	    let session_db = SqliteStorage::new(db_path)?;
242	    let worker_event_tx = if web_config.enabled {
243	        Some(event_tx.clone())
244	    } else {
245	        None
246	    };
247	
248	    tokio::spawn(async move {
249	        storage::worker::run_storage_worker(storage_rx, session_db, worker_event_tx).await;
250	    });
251	
252	    Ok(storage_tx)
253	}
254	
255	fn spawn_web_server_if_enabled(
256	    db_path: &Path,
257	    web_config: &config::WebUiConfig,
258	    event_tx: &broadcast::Sender<AppEvent>,
259	) {
260	    if !web_config.enabled {
261	        return;
262	    }
263	
264	    let web_db_path = db_path.to_path_buf();
265	    let web_event_tx = event_tx.clone();
266	    let web_config = WebConfig {
267	        host: web_config.host.clone(),
268	        port: web_config.port,
269	        auth_token: web_config.token.clone(),
270	    };
271	
272	    tokio::spawn(async move {
273	        if let Err(e) = web::start_web_server(web_config, &web_db_path, web_event_tx).await {
274	            log::error!("Web server error: {e:#}");
275	        }
276	    });
277	}
278	
279	fn resolve_db_path_from_config(config_path: &str) -> Result<PathBuf> {
280	    let config_path = expand_tilde(config_path);
281	    let config = load_config(&config_path)?;
282	    Ok(expand_tilde(&config.db_path))
283	}
284	
285	fn print_help_and_config(config_path: &str) -> Result<()> {
286	    let mut command = Cli::command();
287	    command.print_help()?;
288	    println!();
289	    println!();
290	
291	    let config_path = expand_tilde(config_path);
292	    println!("Config path: {}", config_path.display());
293	    match fs::read_to_string(&config_path) {
294	        Ok(content) => {
295	            println!("Config content:");
296	            println!("{}", content);
297	        }
298	        Err(err) => {
299	            println!("Config content: <unavailable: {}>", err);
300	        }
301	    }
302	
303	    Ok(())
304	}
