102	/// Max message body size to store (1 MB).
103	const MAX_STORED_BODY: usize = 1_048_576;
104	
105	impl MessageContent {
106	    /// Truncate oversized content for storage.
107	    pub fn truncated(self) -> Self {
108	        match self {
109	            MessageContent::Text(s) if s.len() > MAX_STORED_BODY => {
110	                // Find a valid char boundary at or before MAX_STORED_BODY
111	                let mut end = MAX_STORED_BODY;
112	                while !s.is_char_boundary(end) && end > 0 {
113	                    end -= 1;
114	                }
115	                MessageContent::Text(s[..end].to_string())
116	            }
117	            MessageContent::Binary(b) if b.len() > MAX_STORED_BODY => {
118	                MessageContent::Binary(b[..MAX_STORED_BODY].to_vec())
119	            }
120	            other => other,
121	        }
122	    }
123	}
